div.style:
background: linear-gradient(to bottom, #0c0c14 0%, #05050a 100%);
border-bottom: 1px solid rgba(255,255,255,0.08);
padding: 64px 0 48px;
text-align: center;

p.style:
font-family: 'Space Mono', monospace;
font-size: 0.65rem;
letter-spacing: 0.28em;
text-transform: uppercase;
color: #f0c040;
margin-bottom: 16px;
display: flex;
align-items: center;
justify-content: center;
gap: 10px;

h1.style:
font-family: 'Anton', sans-serif;
font-size: clamp(2.5rem, 5vw, 4.5rem);
letter-spacing: 0.03em;
color: #f4f0e8;
line-height: 1;
margin: 0;

p.style:
font-family: 'Outfit', sans-serif;
font-size: 0.9rem;
color: #5a5760;
margin-top: 16px;
font-weight: 300;
